head.script:
//-------------------------------------------------------------------------
// 통장기간의 초기날짜를 구한다. 
//-------------------------------------------------------------------------
scwin.strFromDate = $c.date.getServerDateTime("yyyyMM");

scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin");

scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd");// 사용자소속구분코드 
scwin.loginCoCd = $c.data.getMemInfo("coCd");
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.loginCoCd)?'':scwin.loginCoCd; // 소속 자회사
scwin.loginCoClsCd = $c.data.getMemInfo("coClsCd");
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.loginCoClsCd)?'': scwin.loginCoClsCd;  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)	

scwin.isStarted = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 처리)

//-------------------------------------------------------------------------
// hidden
//------------------------------------------------------------------------
scwin.txtCoClsCd = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    //공통코드 적용
    const codeOptions = [
        { grpCd: "FM010", compID: "lc_bankbookKndCd"},
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    ed_stdYm.setValue(scwin.strFromDate);
    $c.gus.cfDisableKey();
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {

    try {
        //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
        if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
            scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
            scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
        }
        ed_coCd.setValue(scwin.vLoginCoCd);

        scwin.f_PopUpCompanyInfo('T');
    } catch (e) {
       console.log("f_setCompanyInfo: " +e);
    }
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
    /*
    var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
                                ,ed_coCd.text, txt_coNm.value
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null);
    */
    udc_coCd.setSelectId('retrieveDongbuGroupCompanyInfo');
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc // 콜백 함수
                        , ed_coCd.getValue()              // 화면에서의  Code Element의 Value
                        , ed_coNm.getValue()              // 화면에서의  Name Element의 Value
                        , pWinCloseTF                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
};


//-------------------------------------------------------------------------
// 회사코드입력시
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
    scwin.isStarted = false;
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사코드 찾기버튼 클릭시
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.isStarted = false;
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        // SET	 
        if(rtnList != null ) { 
            if (rtnList[0] == "N/A") return false;  
                ed_coCd.setValue(rtnList[0]);	// 코드
                ed_coNm.setValue(rtnList[5]);	// 회사명
                ed_coCd.hidVal = rtnList[0];  // 히든값
                scwin.txtCoClsCd = rtnList[1];	// 회사구분  
        }else{
            ed_coCd.setValue("");	// 코드
            ed_coNm.setValue("");	// 회사명
            ed_coCd.hidVal = "";
            scwin.txtCoClsCd ="";	// 회사구분    
        }

        if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
            scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }

        if(ed_coCd.getValue() =="017"){
            gr_bankbookHisotry.setColumnVisible("ramtFcrc", true);//보이기
            gr_bankbookHisotry.setColumnVisible("rcptAmtFcrc", true);//보이기
            gr_bankbookHisotry.setColumnVisible("withdrawAmtFcrc", true);//보이기
            gr_bankbookHisotry.setColumnVisible("sumRamtFcrc", true);//보이기
        }else{
            gr_bankbookHisotry.setColumnVisible("ramtFcrc", false);//안보이기
            gr_bankbookHisotry.setColumnVisible("rcptAmtFcrc", false);//안보이기
            gr_bankbookHisotry.setColumnVisible("withdrawAmtFcrc", false);//안보이기
            gr_bankbookHisotry.setColumnVisible("sumRamtFcrc", false);//안보이기
        }

        if ( scwin.isStarted == true ) {
            if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
                $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
            }else {
                $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company  ]);   
            }
        }

    } catch (e) {
       console.log("udc_coCd_callBackFunc" + e);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {

    // 필수입력 항목에 대한 내역을 CHECK한다.
    let ret = await $c.gus.cfValidate([ed_stdYm]);
    if (!ret) {
        return false;
    }

    let ret2 = await $c.gus.cfValidate([ed_coCd]);
    if (!ret2) {
        return false;
    }
    ds_bankbookHistory.removeAll();
    $c.sbm.execute(sbm_searchBankbook);
}; 

//-------------------------------------------------------------------------
// 조회 콜백
//-------------------------------------------------------------------------
scwin.sbm_searchBankbook_submitdone = function(e) {

    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

    // 조회된 건수를 Grid 왼쪽 하단에 표시한다.
    tbx_totalRows.setValue($c.gus.cfInsertComma(ds_bankbookHistory.getRowCount()));

    if( ds_bankbookHistory.getRowCount() == 0 ){
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    }
};  

//-------------------------------------------------------------------------
// 엑셀저장
//-------------------------------------------------------------------------
scwin.f_GridToExcel = function() {
    if ( ds_bankbookHistory.getRowCount() <= 0)
    {
        $c.win.alert("통장별원장내역이 존재하지않습니다.");
        return false;
    }
    const options = {
        fileName : "통장별원장내역.xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        ,sheetName : "통장별원장내역" //엑셀내 시트명 지정필요시
    };
    const infoArr = [];
    $c.data.downloadGridViewExcel(gr_bankbookHisotry, options, infoArr);
}

//-------------------------------------------------------------------------
// 통장번호
//-------------------------------------------------------------------------
scwin.udc_Bankbook_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_bankbookNo, ed_txt_bankbookNm,'1');
};

//-------------------------------------------------------------------------
// 통장명찾기
//-------------------------------------------------------------------------
scwin.udc_Bankbook_onclickEvent = function (e) {
    scwin.f_openPopUp('1',ed_bankbookNo,ed_txt_bankbookNm,'F')
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm,select_code) {
    try {
        if (orgObjCd.getValue() !=  orgObjCd.hidVal) {
            if ( !(orgObjNm == null) )
            orgObjNm.setValue("");
        }

        if (orgObjCd.getValue().trim() != "") {
		    scwin.f_openPopUp(select_code,orgObjCd,orgObjNm,'T');

        }else{
            if ( !(orgObjNm == null) ){
                orgObjNm.setValue("");
            }
            orgObjCd.setValue("");
            orgObjCd.hidVal = "";
        }
    } catch (e) {
       console.log("f_CheckPopUp : " + e);
    }
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:검색->관리부서 , 2:검색->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (select_code,txtCode,txtName,sFlag) {
    try {
        let code = txtCode.getValue();
        let name = txtName.getValue();
        let param = "";

        switch (select_code) {
            // 통장조회
            case '1' :
                param = ","+","+","+","+","+ed_coCd.getValue()+","+scwin.txtCoClsCd+",0";
                //rtnList = cfCommonPopUp('retrieveBankBookCdInfo',code,name,sFlag,null,null,null,null,param,null,"F",null,null); // 통장
                udc_Bankbook.setSelectId('retrieveBankBookCdInfo');
                udc_Bankbook.cfCommonPopUp(scwin.udc_Bankbook_callBackFunc // 콜백 함수
                        , code                            // 화면에서의 ??? Code Element의 Value
                        , name                            // 화면에서의 ??? Name Element의 Value
                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                          // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                           // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                           // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , 'F'                             // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
                break;
        }

    } catch (e) {
       console.log("f_CheckPopUp : " + e);
    }
};        

//-------------------------------------------------------------------------
// 통장명 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_Bankbook_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if ( rtnList[0] == "N/A" ) return ;
			ed_bankbookNo.setValue(rtnList[0]);	// 코드
            ed_txt_bankbookNm.setValue(rtnList[2]);	// 코드명
            ed_bankbookNo.hidVal = rtnList[0];	// 코드

		} else {
			ed_bankbookNo.setValue("");
            ed_txt_bankbookNm.setValue("");
            ed_bankbookNo.hidVal = "";
		}
    } catch (e) {
       console.log("udc_Bankbook_callBackFunc : " + e);
    }
};
